mapper.select:
SELECT

    ,
    yy.property_money as yy_money,zr.property_money as zr_money,zl.property_money as zl_money
FROM property_info t0
left join (
  select
      aid.property_id,sum(aid.property_money) as property_money
  from operation_info oi
  left join asset_income_distribution aid on oi.id=aid.do_id
  where oi.flow_state='completed' and aid.property_id is not null

    AND aid.property_date BETWEEN

      #{item}


  GROUP BY aid.property_id
) yy on t0.id=yy.property_id left join (
  select
      aid.property_id,sum(aid.property_money) as property_money
  from asset_transfer t
  left join asset_income_distribution aid on t.id=aid.do_id
  where t.flow_state='completed' and aid.property_id is not null

    AND aid.property_date BETWEEN

      #{item}


  GROUP BY aid.property_id
) zr on t0.id=zr.property_id left join (
  select
      property_id,sum(property_money) as property_money
  from asset_income_distribution
  where do_type='LEASE_PAYMENT_CYCLE' and property_id is not null

    AND property_date BETWEEN

      #{item}


  GROUP BY property_id
) zl on t0.id=zl.property_id


    AND t0.create_stamp BETWEEN

      #{item}



    AND t0.property_end_date BETWEEN

      #{item}



    AND t0.id = #{request.id}


    AND t0.follow_up_person LIKE CONCAT('%',#{request.followUpPerson},'%')


    AND t0.id in

      #{item}



    AND t0.id not in

      #{item}



    AND t0.property_tag LIKE CONCAT('%', #{request.createStamp},'%')


    AND t0.property_state = #{request.propertyState}


    AND t0.property_state in

      #{item}



    AND t0.tenant_id = #{request.tenantId}


    AND t0.creator = #{request.creator}


    AND t0.create_stamp = #{request.createStamp}


    AND t0.last_editor = #{request.lastEditor}


    AND t0.last_edit_stamp = #{request.lastEditStamp}


    AND t0.property_state = #{request.propertyState}


    AND t0.property_name LIKE CONCAT('%', #{request.propertyName},'%')


    AND t0.project_name LIKE CONCAT('%', #{request.projectName},'%')


    AND t0.type = #{request.type}


    AND t0.property_type = #{request.propertyType}


    AND t0.source_type = #{request.sourceType}


    AND t0.project_id = #{request.projectId}


    AND t0.reve_id = #{request.reveId}


    AND t0.province = #{request.province}


    AND t0.city = #{request.city}


    AND t0.district = #{request.district}


    AND t0.address = #{request.address}


    AND t0.label = #{request.label}


    AND t0.access_way = #{request.accessWay}


    AND t0.property_describe = #{request.propertyDescribe}


    AND t0.area = #{request.area}


    AND t0.asset_use = #{request.assetUse}


    AND t0.property_code LIKE CONCAT('%', #{request.propertyCode},'%')


    AND t0.property_end_date = #{request.propertyEndDate}


    AND t0.property_transfer_ownership = #{request.propertyTransferOwnership}


    AND t0.transfer_ownership_remark = #{request.transferOwnershipRemark}


    AND t0.debt_repayment_money = #{request.debtRepaymentMoney}


    AND t0.original_value = #{request.originalValue}


    AND t0.net_worth = #{request.netWorth}


    AND t0.disposal_price = #{request.disposalPrice}


    AND t0.Taxe_fee = #{request.taxeFee}


    AND t0.original_obligor_fee = #{request.originalObligorFee}


    AND t0.profit_and_loss = #{request.profitAndLoss}


    AND t0.is_deleted = #{request.isDeleted}




    ORDER BY ${request.field} ${request.order}


    ORDER BY t0.id DESC
